// // This module implements a binary down-counter that counts from 15 to 0.
module binary_up_counter(
        input clk,
        input reset,
        output reg [3:0] count);

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            count <= 4'b0000;
        end else begin
            count <= count + 1;
        end
    end
endmodule
